// Converting Entity Type to Relation
CREATE RELATION STUDENT(
 roll_no PRIMARY KEY,
 name VARCHAR(50),
 age INTEGER,
 dob DATE
);

// For Composite Attribute - only store simple components
CREATE RELATION ADDRESS(
 student_id PRIMARY KEY,
 street VARCHAR(100),
 city VARCHAR(50),
 state VARCHAR(50),
 zip_code VARCHAR(10)
);

// For Multi-valued Attribute - create separate relation
CREATE RELATION PHONE_NUMBERS(
 student_id,
 phone_number,
 PRIMARY KEY (student_id, phone_number)
);

// Strong Entity first
CREATE RELATION EMPLOYEE(
 emp_id PRIMARY KEY,
 emp_name VARCHAR(50),
 salary INTEGER
);

// Weak Entity - includes owner's primary key
CREATE RELATION DEPENDENT(
 emp_id,
 dependent_name,
 relationship VARCHAR(20),
 PRIMARY KEY (emp_id, dependent_name),
 FOREIGN KEY (emp_id) REFERENCES EMPLOYEE
);

// 1:1 Relationship - embed foreign key
CREATE RELATION PROFESSOR(
 prof_id PRIMARY KEY,
 name VARCHAR(50),
 dept_id FOREIGN KEY REFERENCES DEPARTMENT
);

// 1:N Relationship - foreign key on 'many' side
CREATE RELATION DEPARTMENT(
 dept_id PRIMARY KEY,
 name VARCHAR(50)
);
CREATE RELATION STUDENT(
 roll_no PRIMARY KEY,
 name VARCHAR(50),
 dept_id FOREIGN KEY REFERENCES DEPARTMENT
);

// M:N Relationship - separate junction table
CREATE RELATION ENROLLMENT(
 student_id,
 course_id,
 grade VARCHAR(5),
 PRIMARY KEY (student_id, course_id)
);
